import { supabase } from '../lib/supabase'

export async function syncFmExecutions(planId: number): Promise<{ created: number }> {
  const { data, error } = await supabase.functions.invoke<{ created: number }>(
    'daily-sync-fm-executions',
    { body: { planId } }
  )
  if (error) throw error
  if (!data) throw new Error('No data returned')
  return data
}

export async function rebuildFmExecutions(
  planId: number
): Promise<{ deleted: number; created: number }> {
  const { data, error } = await supabase.functions.invoke<{ deleted: number; created: number }>(
    'rebuild-fm-executions',
    { body: { planId } }
  )
  if (error) throw error
  if (!data) throw new Error('No data returned')
  return data
}
