import { useEffect, useState } from 'react'

import { useParams, Link } from 'react-router-dom'

import { ArrowBack as BackIcon } from '@mui/icons-material'
import { Box, Button, CircularProgress, Alert } from '@mui/material'

import { getTrainingPlan } from '@/api/trainingPlans'
import { routes } from '@/routes'
import type { TrainingPlan } from '@/types/database'

import PlanCard from '../components/PlanCard'

export function PlansDetailPage() {
  const { id } = useParams<{ id: string }>()
  const [plan, setPlan] = useState<TrainingPlan | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (id) {
      loadPlan(Number(id))
    }
  }, [id])

  async function loadPlan(planId: number) {
    try {
      setLoading(true)
      const data = await getTrainingPlan(planId)
      setPlan(data)
    } catch (err) {
      setError('훈련 계획을 불러오는데 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
        <CircularProgress />
      </Box>
    )
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>
  }

  if (!plan) {
    return <Alert severity="warning">훈련 계획을 찾을 수 없습니다.</Alert>
  }

  return (
    <Box>
      <Button component={Link} to={routes.plans.$()} startIcon={<BackIcon />} sx={{ mb: 2 }}>
        목록으로
      </Button>

      <PlanCard plan={plan} showInfo variant="detail" onUpdate={() => loadPlan(Number(id))} />
    </Box>
  )
}
