import { useState, memo } from 'react'

import { Link, useNavigate } from 'react-router-dom'

import {
  CalendarToday,
  Info as InfoIcon,
  InfoOutline as InfoOutlineIcon,
  AutoFixHigh as AutoFixHighIcon,
  CheckCircle as CheckCircleIcon,
} from '@mui/icons-material'
import {
  Typography,
  Box,
  Button,
  Card,
  CardContent,
  CardActions,
  Stack,
  Chip,
  CircularProgress,
  LinearProgress,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogContentText,
  DialogActions,
  Alert,
} from '@mui/material'

import { syncFmExecutions, rebuildFmExecutions } from '@/api/fmSync'
import { deleteTrainingPlan, updateTrainingPlan } from '@/api/trainingPlans'
import { PlanExecutionButton } from '@/components/PlanExecutionButton'
import { usePlanProgress, useTrainingExecutions } from '@/hooks/useTrainingExecutions'
import { routes } from '@/routes'
import type { TrainingPlan } from '@/types/database'
import {
  calculateTotalSessions,
  calculateEndDate,
  formatDate,
  getWeekDayLabel,
} from '@/utils/schedule'
import { renderUnit } from '@/utils/unit-utils'

function formatDuration(seconds: number): string {
  if (seconds === 0) return '-'
  const minutes = Math.floor(seconds / 60)
  const secs = seconds % 60
  if (minutes === 0) return `${secs}초`
  return `${minutes}분 ${secs}초`
}

function parseFmUrl(unitName: string): { owner: string; repo: string; path?: string } | null {
  if (!unitName.startsWith('fm://')) return null
  const parts = unitName.replace('fm://', '').split('/')
  if (parts.length < 2) return null
  return {
    owner: parts[0],
    repo: parts[1],
    path: parts.length > 2 ? parts.slice(2).join('/') : undefined,
  }
}

export type Props = {
  plan: TrainingPlan
  showInfo?: boolean
  variant: 'list' | 'detail'
  onUpdate?: () => void
}

function PlanCard({ plan, variant, showInfo: showInfoOrig, onUpdate }: Props) {
  const [generating, setGenerating] = useState(false)
  const [genResult, setGenResult] = useState<string | null>(null)

  const totalSessions = calculateTotalSessions(plan)
  const fmInfo = parseFmUrl(plan.unit_name)

  const { isLoading, data: progress, refetch } = usePlanProgress(plan.id)
  const { data: executions } = useTrainingExecutions(plan.id)
  const endDate = calculateEndDate(plan, executions)

  async function handleAutoGenerate(rebuild = false) {
    if (!fmInfo) return
    setGenerating(true)
    setGenResult(null)
    try {
      if (rebuild) {
        const result = await rebuildFmExecutions(plan.id)
        setGenResult(`삭제: ${result.deleted}, 생성: ${result.created}`)
      } else {
        const result = await syncFmExecutions(plan.id)
        setGenResult(`생성: ${result.created}`)
      }
      await refetch()
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err)
      setGenResult('오류가 발생했습니다.')
    } finally {
      setGenerating(false)
    }
  }

  const progressPercent = progress
    ? Math.min(100, Math.round((progress.completedUnits / plan.total_amount) * 100))
    : 0

  const [showInfo, setShowInfo] = useState(showInfoOrig)
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false)
  const [deleting, setDeleting] = useState(false)
  const [completing, setCompleting] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function handleToggleComplete() {
    try {
      setCompleting(true)
      await updateTrainingPlan(plan.id, {
        completed_at: plan.completed_at ? null : new Date().toISOString(),
      })
      onUpdate?.()
    } catch (err) {
      setError('완료 처리에 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setCompleting(false)
    }
  }

  const navigate = useNavigate()
  async function handleDelete() {
    if (!plan) return

    try {
      setDeleting(true)
      await deleteTrainingPlan(plan.id)
      navigate(routes.plans.$())
    } catch (err) {
      setError('삭제에 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setDeleting(false)
      setDeleteDialogOpen(false)
    }
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>
  }

  return (
    <Card>
      <CardContent>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: '0.4' }}>
            <CalendarToday sx={{ mr: 1, verticalAlign: 'middle' }} />
            <Typography variant="h6">{plan.name}</Typography>
            {plan.completed_at && (
              <Chip
                icon={<CheckCircleIcon />}
                label={`완료 ${formatDate(new Date(plan.completed_at))}`}
                size="small"
                color="success"
                sx={{ ml: 1 }}
              />
            )}
          </Box>
          {!showInfoOrig && (
            <IconButton onClick={() => setShowInfo(!showInfo)}>
              {showInfo ? <InfoIcon /> : <InfoOutlineIcon />}
            </IconButton>
          )}
        </Box>
        {showInfo && (
          <>
            <Stack direction="row" flexWrap={'wrap'} spacing={1} sx={{ mb: 1 }}>
              <Chip
                label={`${plan.unit_amount} ${renderUnit(plan.unit_name)}/회`}
                size="small"
                variant="outlined"
              />
              <Chip
                label={`총 ${plan.total_amount} ${renderUnit(plan.unit_name)}`}
                size="small"
                variant="outlined"
              />
              <Chip
                label={
                  plan.schedule_type === 'daily'
                    ? '매일'
                    : `매주 ${plan.schedule_days?.map(getWeekDayLabel).join(', ')}`
                }
                size="small"
                variant="outlined"
              />
            </Stack>
          </>
        )}

        {/* Progress Section */}
        {isLoading ? (
          <LinearProgress sx={{ my: 1 }} />
        ) : (
          progress && (
            <Box>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
                <Typography variant="body2" color="text.secondary">
                  진행률
                </Typography>
                <Typography variant="body2" fontWeight="medium">
                  {progress.completedUnits} / {plan.total_amount} {renderUnit(plan.unit_name)} (
                  {progressPercent}
                  %)
                </Typography>
              </Box>
              <LinearProgress
                variant="determinate"
                value={progressPercent}
                sx={{ height: 8, borderRadius: 1, mb: 1 }}
              />
              {showInfo && (
                <Stack direction="row" spacing={2} sx={{ mt: 1 }} justifyContent="space-between">
                  <Box>
                    <Typography variant="caption" color="text.secondary">
                      평균 시간: <strong>{formatDuration(progress.avgDurationSeconds)}</strong>•
                      평균 수행량:{' '}
                      <strong>
                        {progress.avgUnitCount} {renderUnit(plan.unit_name)}
                      </strong>
                    </Typography>
                  </Box>
                  <Box>
                    <Typography variant="caption" color="text.secondary">
                      수행: <strong>{progress.totalExecutions}회</strong>
                    </Typography>
                  </Box>
                </Stack>
              )}
            </Box>
          )
        )}
        <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
          <Typography variant="body2" color="text.secondary">
            총 {totalSessions}회
          </Typography>
          <Typography variant="body2" color="text.secondary">
            종료 예정: <strong>{formatDate(endDate)}</strong>
          </Typography>
        </Box>
      </CardContent>
      {genResult && (
        <Box sx={{ px: 2, pb: 1 }}>
          <Typography variant="caption" color="text.secondary">
            {genResult}
          </Typography>
        </Box>
      )}
      {variant === 'list' && (
        <CardActions sx={{ justifyContent: 'space-between' }}>
          <Box sx={{ display: 'flex', gap: 1 }}>
            <Button
              component={Link}
              to={routes.plans.detail.$path({ id: plan.id }, {})}
              size="small"
            >
              상세보기
            </Button>
          </Box>
          <PlanExecutionButton plan={plan} size="small" variant="contained" />
        </CardActions>
      )}
      {variant === 'detail' && (
        <>
          <CardActions sx={{ justifyContent: 'space-between' }}>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <Button
                component={Link}
                to={routes.plans.edit.$path({ id: plan.id }, {})}
                variant="outlined"
                // startIcon={<EditIcon />}
              >
                수정
              </Button>
              {fmInfo && (
                <>
                  <Button
                    startIcon={generating ? <CircularProgress size={16} /> : <AutoFixHighIcon />}
                    size="small"
                    color="warning"
                    variant="outlined"
                    onClick={() => handleAutoGenerate(true)}
                    disabled={generating}
                  >
                    재생성
                  </Button>
                </>
              )}
              <Button
                variant="outlined"
                color="error"
                // startIcon={<DeleteIcon />}
                onClick={() => setDeleteDialogOpen(true)}
              >
                삭제
              </Button>
            </Box>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <Button
                variant={plan.completed_at ? 'outlined' : 'contained'}
                color="success"
                startIcon={completing ? <CircularProgress size={16} /> : <CheckCircleIcon />}
                onClick={handleToggleComplete}
                disabled={completing}
              >
                {plan.completed_at ? '완료 취소' : '완료'}
              </Button>
              {!plan.completed_at && <PlanExecutionButton plan={plan} variant="contained" />}
            </Box>
          </CardActions>

          <Dialog open={deleteDialogOpen} onClose={() => setDeleteDialogOpen(false)}>
            <DialogTitle>훈련 계획 삭제</DialogTitle>
            <DialogContent>
              <DialogContentText>
                "{plan.name}" 계획을 삭제하시겠습니까? 이 작업은 되돌릴 수 없습니다.
              </DialogContentText>
            </DialogContent>
            <DialogActions>
              <Button onClick={() => setDeleteDialogOpen(false)} disabled={deleting}>
                취소
              </Button>
              <Button onClick={handleDelete} color="error" disabled={deleting}>
                {deleting ? '삭제 중...' : '삭제'}
              </Button>
            </DialogActions>
          </Dialog>
        </>
      )}
    </Card>
  )
}

export default memo(PlanCard)
